<script>
	export default {
		onShow() {},
		onLaunch() {},
		onHide() {}
	}
	//жУНдљЬжХ∞жНЃеЇУеѓєи±°
	export function objValue(tablename, api, id, name, phone, time, status) {
		// objValue(tablename, api, id, name, phone, time, status)
		// objValue(и°®еРН,ињЫи°МзЪДapiжМЗдї§,иЃЊе§Зid,еІУеРН,жЙЛжЬЇеПЈ,жЧґйЧі,зКґжАБ)ж≤°жЬЙе°Ђnull
		const object = {
			tablename: tablename,
			api: api,
			id: id,
			name: name,
			phone: phone,
			time: time,
			status: status
		}
		return object
	}
	//жУНдљЬжХ∞жНЃеЇУеЗљжХ∞
	export function execSql(name, data, callback) {
		//execSql(дЇСеЗљжХ∞еРН,dataеѓєи±°,еЫЮи∞ГеЗљжХ∞)
		uniCloud.callFunction({
			name: name,
			data: data
		}).then(res => {
			callback(res);
		})
	}
	//ињФеЫЮеєіжЬИжЧ•жЧґеИЖзІТ
	export function time() {
		const date = new Date();
		const year = date.getFullYear();
		let month = date.getMonth() + 1;
		let day = date.getDate();
		let h = date.getHours();
		let m = date.getMinutes();
		let s = date.getSeconds();
		month <= 9 ? month = "0" + month : false
		day <= 9 ? day = "0" + day : false
		h <= 9 ? h = "0" + h : false
		m <= 9 ? m = "0" + m : false
		s <= 9 ? s = "0" + s : false
		let time = year + "еєі" + month + "жЬИ" + day + "жЧ•" + h + ":" + m + ":" + s
		return time
	}
	//е§НеИґеИ∞еЙ™иііжЭњ
	export function setClipboard(data) {
		//data  дЉ†еЕ•йЬАи¶Бе§НеИґзЪДеЖЕеЃє
		uni.setClipboardData({
			data: data,
			success: function() {
				uni.showToast({
					title: 'е§НеИґжИРеКЯ',
					icon: 'success'
				})
			}
		});
	}
	//иЗ™еЃЪдєЙиЈ≥иљђ
	export function router(url) {
		uni.navigateTo({
			url: '/pages/' + url + '/' + url
		})
	}
</script>

